import React, { useEffect, useState } from "react";
import axios from "axios";

export default function ListaPeriodos({ onEditar, reloadKey }) {
  const [periodos, setPeriodos] = useState([]);
  const [carregando, setCarregando] = useState(true);

  useEffect(() => {
  setCarregando(true);
  axios
    .get("/api/periodos")
    .then((res) => {
      setPeriodos(res.data);
      setCarregando(false);
    })
    .catch(() => setCarregando(false));
}, [reloadKey]);

  const handleDeletar = (id) => {
    if (window.confirm("Tem certeza que deseja deletar este período?")) {
      axios
        .delete(`/api/periodos/${id}`)
        .then(() => setPeriodos(periodos.filter((p) => p.id !== id)));
    }
  };

  if (carregando) return <p>Carregando períodos...</p>;
  if (periodos.length === 0) return <p>Nenhum período cadastrado.</p>;

  return (
    <div className="mt-4">
  <h2 className="text-xl font-semibold mb-4 text-[#1d3557]">Lista de Períodos</h2>
  {/* Cabeçalho de colunas */}
  <div className="flex px-5 pb-2 text-gray-500 font-bold text-sm">
    <div className="w-1/2">Período</div>
    <div className="w-1/4">Turno</div>
    <div className="w-1/4 text-right">Ações</div>
  </div>
  {/* Lista de cards */}
  <ul className="space-y-3">
    {periodos.map((p) => (
      <li
        key={p.id}
        className="flex items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm hover:bg-gray-100 transition"
      >
        <div className="w-1/2 font-medium text-gray-800">{p.nome}</div>
        <div className="w-1/4 text-gray-500">{p.turno}</div>
        <div className="w-1/4 flex justify-end space-x-2">
          <button
            onClick={() => onEditar && onEditar(p)}
            className="px-4 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
          >
            Editar
          </button>
          <button
            onClick={() => handleDeletar(p.id)}
            className="px-4 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
          >
            Deletar
          </button>
        </div>
      </li>
    ))}
  </ul>
</div>




  );
}
